package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
)

func uploadFile(w http.ResponseWriter, r *http.Request) {
	r.ParseMultipartForm(10 << 20) // Max memory 10MB
	file, handler, err := r.FormFile("myFile")
	if err != nil {
		fmt.Println("Error Retrieving the File")
		fmt.Println(err)
		return
	}
	defer file.Close()

	// Create a new file in the uploads directory that follows the pattern: "upload-{UNIX timestamp}.extension"
	ext := handler.Filename[len(handler.Filename)-4:] // Get extension from filename
	fmt.Printf("File Type: %s\n", ext)
	newFileName := fmt.Sprintf("./public/upload-%d%s", time.Now().Unix(), ext)
	newFile, err := os.OpenFile(newFileName, os.O_WRONLY|os.O_CREATE, 0666)
	if err != nil {
		fmt.Println(err)
		return
	}
	defer newFile.Close()

	// Write the file to the newly created file
	_, err = io.Copy(newFile, file)
	if err != nil {
		fmt.Fprintf(w, "Error while saving the file: %s", err)
	} else {
		fmt.Fprintf(w, "/%s\n", newFileName) // Return the file path
	}
}

func main() {
	// Create a static directory to serve files from
	fs := http.FileServer(http.Dir("./public"))
	http.Handle("/", fs)

	// Register our handler for /upload endpoint
	http.HandleFunc("/upload", uploadFile)
	fmt.Println("Listening on port 8080")
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		log.Fatal(err)
	}
}